args.query:
SELECT id, subject, description, status, contactid, accountid, createddate
FROM "Case"
WHERE REPLACE(contactid,'#','') IN (
  SELECT REPLACE(ConvertedContactId,'#','') FROM Lead WHERE REPLACE(Id,'#','')='00QWt0000089AekMAE'
)
OR REPLACE(accountid,'#','') IN (
  SELECT REPLACE(ConvertedAccountId,'#','') FROM Lead WHERE REPLACE(Id,'#','')='00QWt0000089AekMAE'
)
ORDER BY createddate DESC
LIMIT 20;

